function verdictRank(verdict: string) {
  if (verdict === "strong-value") return 5;
  if (verdict === "lean-value") return 4;
  if (verdict === "watchlist") return 3;
  if (verdict === "avoid") return 2;
  return 1;
}

function statusClass(status: ReadinessStatus) {
  if (status === "ready") return "positive";
  if (status === "warning") return "medium";
  return "no-value";
}

function formatTime(value: string): string {
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return "Unknown";
  return date.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });
}

function compactMetric(value: string, maxLength = 82): string {
  return value.length > maxLength ? `${value.slice(0, maxLength - 3)}...` : value;
}

type DecisionEngineSearchParams = Record<string, string | string[] | undefined>;
type DecisionEnginePageProps = {
  searchParams?: Promise<DecisionEngineSearchParams>;
};
type DecisionRow = Awaited<ReturnType<typeof getPredictions>>[number];
type FastEplOddsIdentitySummary = {
  status: "matched" | "missing";
  match: string | null;
  matchId: string | null;
  fixtureId: string | null;
  eventId: string | null;
  fixtureProvider: string | null;
  oddsProvider: string | null;
  kickoffTime: string | null;
  nextAction: string;
};

function isEnabledSearchParam(value: string | string[] | undefined): boolean {
  const normalized = Array.isArray(value) ? value[0] : value;
  return normalized === "1" || normalized === "true" || normalized === "yes";
}

function firstSearchParam(value: string | string[] | undefined): string | undefined {
  return Array.isArray(value) ? value[0] : value;
}

function optionalSearchParam(value: string | string[] | undefined): string | undefined {
  const normalized = firstSearchParam(value)?.replace(/\s+/g, " ").trim();
  return normalized ? normalized : undefined;
}

function pageDateFromParams(params: DecisionEngineSearchParams): string {
  const date = firstSearchParam(params.date)?.trim();
  return date && /^\d{4}-\d{2}-\d{2}$/.test(date) ? date : todayIsoDate();
}

function buildFastEplOddsIdentitySummary(rows: DecisionRow[]): FastEplOddsIdentitySummary {
  const row =
    rows.find((item) => item.match.id.startsWith("the-odds-api:") && item.match.dataSource?.oddsProvider === "the-odds-api") ??
    rows.find((item) => item.match.dataSource?.fixtureProvider === "the-odds-api-events") ??
    rows.find((item) => item.match.dataSource?.oddsProvider === "the-odds-api" && item.match.oddsMarkets.length > 0) ??
    null;
  if (!row) {
    return {
      status: "missing",
      match: null,
      matchId: null,
      fixtureId: null,
      eventId: null,
      fixtureProvider: null,
      oddsProvider: null,
      kickoffTime: null,
      nextAction: "Fetch a same-date The Odds API event, then map it to the official EPL fixture seed and API-Football/APISports fixture ID."
    };
  }
  const eventId =
    row.match.dataSource?.oddsProviderEventId ??
    (row.match.id.startsWith("the-odds-api:") ? row.match.id.replace("the-odds-api:", "") || null : null);
  return {
    status: eventId ? "matched" : "missing",
    match: `${row.match.homeTeam.name} vs ${row.match.awayTeam.name}`,
    matchId: row.match.id,
    fixtureId: row.match.dataSource?.fixtureProviderId ?? null,
    eventId,
    fixtureProvider: row.match.dataSource?.fixtureProvider ?? null,
    oddsProvider: row.match.dataSource?.oddsProvider ?? null,
    kickoffTime: row.match.kickoffTime,
    nextAction: eventId
      ? "Fixture and bookmaker event identities are linked. Keep the market read-only while standings, availability, lineups, and near-kickoff context are refreshed."
      : "Odds are attached, but the bookmaker event ID is missing from provenance. Refresh the provider mapping before trusting market identity."
  };
}

function compactJournalHash(value: unknown): string {
  const input = JSON.stringify(value);
  let hash = 2166136261;
  for (let index = 0; index < input.length; index += 1) {
    hash ^= input.charCodeAt(index);
    hash = Math.imul(hash, 16777619);
  }
  return `fnv1a-${(hash >>> 0).toString(16).padStart(8, "0")}`;
}

function buildLocalCompactThoughtJournal({
  date,
  rows,
  publicHistoricalTrainingEvidence,
  openAiKeyDiagnostic
}: {
  date: string;
  rows: DecisionRow[];
  publicHistoricalTrainingEvidence: PublicHistoricalTrainingEvidence | null;
  openAiKeyDiagnostic: DecisionOpenAIKeyDiagnostic;
}): DecisionThoughtJournal | null {
  const row = rows[0] ?? null;
  if (!row) return null;
  const discipline = row.prediction.decision.historicalDiscipline;
  const bestPick = row.prediction.bestPick;
  const openAiReady = openAiKeyDiagnostic.runtime.canRunLiveReview;
  const activeMatch = `${row.match.homeTeam.name} vs ${row.match.awayTeam.name}`;
  const historyStatus =
    discipline.trustEffect === "block" || discipline.trustEffect === "cap-raw-edge"
      ? "block"
      : discipline.trustEffect === "queue-provider-retest"
        ? "need-evidence"
        : discipline.attached
          ? "question"
          : "need-evidence";
  const entries: DecisionThoughtJournal["entries"] = [
    {
      id: "thought-historical-discipline",
      phase: "decide",
      status: historyStatus,
      title: "Historical discipline",
      observation: `${discipline.summary} ${discipline.instruction}`,
      evidence: [
        discipline.source ?? "public-history-not-attached",
        discipline.seasons ?? "seasons-pending",
        `fixtures:${discipline.fixtures}`,
        `oddsRows:${discipline.oddsRows}`,
        `benchmark:${discipline.benchmarkVerdict ?? "pending"}`
      ],
      confidenceImpact: historyStatus === "block" ? -34 : historyStatus === "need-evidence" ? -18 : -8,
      nextCheck: discipline.requiredBeforePromotion[0] ?? "Provider fixture identity must be proven before promotion."
    },
    {
      id: "thought-market-edge",
      phase: "weigh",
      status: bestPick.hasValue ? "question" : "need-evidence",
      title: bestPick.hasValue ? bestPick.label : "No clear value found",
      observation: bestPick.hasValue
        ? `${bestPick.label} has model probability ${(bestPick.modelProbability * 100).toFixed(1)}% and no-vig edge ${(bestPick.edge * 100).toFixed(1)}%, but promotion still depends on history and provider proof.`
        : "No selection clears the positive value edge, confidence, and evidence gates.",
      evidence: bestPick.hasValue
        ? [`odds:${bestPick.odds.toFixed(2)}`, `edge:${bestPick.edge.toFixed(4)}`, `ev:${bestPick.expectedValue.toFixed(4)}`]
        : ["no-value-pick"],
      confidenceImpact: bestPick.hasValue ? 8 : -14,
      nextCheck: "Compare the model edge with no-vig market consensus and latest team context before any public action."
    },
    {
      id: "thought-ai-review",
      phase: "verify",
      status: openAiReady ? "question" : "need-evidence",
      title: "AI review gate",
      observation: openAiReady
        ? "OpenAI key is configured, but journal output remains no-persistence and must obey the safety gates."
        : "OpenAI review is not available, so deterministic controls remain in charge.",
      evidence: [openAiKeyDiagnostic.status, openAiKeyDiagnostic.summary],
      confidenceImpact: openAiReady ? 4 : -10,
      nextCheck: openAiReady ? "Run live AI review only after evidence gates are attached." : "Restore OpenAI quota/config before live AI critique."
    }
  ];
  const blocks = entries.filter((entry) => entry.status === "block").length;
  const needsEvidence = entries.filter((entry) => entry.status === "need-evidence").length;
  const questions = entries.filter((entry) => entry.status === "question").length;
  const support = entries.filter((entry) => entry.status === "support").length;
  const score = Math.max(0, Math.min(100, 58 + entries.reduce((total, entry) => total + entry.confidenceImpact, 0)));
  const status: DecisionThoughtJournal["status"] = blocks > 0 ? "blocked" : needsEvidence > 0 ? "waiting-for-evidence" : "review-ready";
  const journalHash = compactJournalHash({
    date,
    matchId: row.match.id,
      discipline: discipline.status,
      trustEffect: discipline.trustEffect,
      openAi: openAiKeyDiagnostic.status,
    publicHistory: publicHistoricalTrainingEvidence?.status ?? null
  });

  return {
    generatedAt: new Date().toISOString(),
    date,
    sport: "football",
    mode: "decision-thought-journal",
    status,
    journalHash,
    summary:
      blocks > 0
        ? `Thought journal recorded ${entries.length} compact steps and ${blocks} blocking thought(s); the active belief cannot promote.`
        : `Thought journal recorded ${entries.length} compact steps; the active belief remains supervised until evidence gates clear.`,
    activeBelief: {
      matchId: row.match.id,
      match: activeMatch,
      authorizedAction: row.prediction.decision.action,
      publicPosture: status === "blocked" ? "internal-only" : "watchlist-only",
      source: status === "blocked" ? "proof-blocked" : "deterministic",
      movement: status === "blocked" ? "blocked" : "held",
      reason: discipline.summary
    },
    confidencePulse: {
      score,
      grade: score >= 70 ? "high" : score >= 45 ? "medium" : "low",
      netThoughtPressure: entries.reduce((total, entry) => total + entry.confidenceImpact, 0),
      support,
      questions,
      needsEvidence,
      blocks
    },
    entries,
    nextEvidenceAction: discipline.requiredBeforePromotion[0] ?? "Provider fixture identity must be proven before promotion.",
    changeTriggers: [
      "Provider fixture identity is mapped to live API-Football/APISports event IDs.",
      "No-vig market benchmark no longer beats the model on comparable public-history samples.",
      "OpenAI review is available and cites the same evidence without upgrading risk."
    ],
    controls: {
      canInspect: true,
      canSubmitToOpenAI: openAiReady,
      canPromote: false,
      canPersist: false,
      canPublish: false,
      canTrain: false,
      canUpgradePublicAction: false
    },
    aiReview: {
      requested: false,
      provider: openAiReady ? "openai" : "deterministic",
      status: openAiReady ? "not-requested" : "not-configured",
      model: openAiReady ? openAiKeyDiagnostic.runtime.model : null,
      reviewHash: null,
      reason: openAiKeyDiagnostic.summary,
      review: null,
      safeNoPersistence: true
    },
    proofUrls: [
      `/api/sports/decision/thought-journal?date=${date}&sport=football${publicHistoricalTrainingEvidence ? "&publicHistory=1" : ""}`,
      `/api/sports/decision/historical-discipline?date=${date}&sport=football&historical=1&publicHistory=1`
    ]
  };
}

function rankDecisionRows(rows: DecisionRow[]): DecisionRow[] {
  return rows
    .slice()
    .sort((a, b) => {
      const verdictDiff = verdictRank(b.prediction.decision.verdict) - verdictRank(a.prediction.decision.verdict);
      if (verdictDiff !== 0) return verdictDiff;
      const aEv = a.prediction.bestPick.hasValue ? a.prediction.bestPick.expectedValue : -1;
      const bEv = b.prediction.bestPick.hasValue ? b.prediction.bestPick.expectedValue : -1;
      if (bEv !== aEv) return bEv - aEv;
      const aEdge = a.prediction.bestPick.hasValue ? a.prediction.bestPick.edge : -1;
      const bEdge = b.prediction.bestPick.hasValue ? b.prediction.bestPick.edge : -1;
      if (bEdge !== aEdge) return bEdge - aEdge;
      return b.match.dataQualityScore - a.match.dataQualityScore;
    });
}

function summarizeRows(rows: DecisionRow[]) {
  const counts = rows.reduce(
    (acc, row) => {
      acc[row.prediction.decision.action] += 1;
      return acc;
    },
    { consider: 0, monitor: 0, avoid: 0 }
  );
  const healthCounts = rows.reduce(
    (acc, row) => {
      acc[row.prediction.decision.health] += 1;
      return acc;
    },
    { stable: 0, review: 0, fragile: 0 }
  );
  return { counts, healthCounts };
}

function mvpLaneClass(status: DecisionMvpProgressSnapshot["lanes"][number]["status"]) {
  if (status === "done") return "positive";
  if (status === "current") return "medium";
  return "no-value";
}

